+
+        let (sy, cy) = self.player.yaw.sin_cos();
+        let (sp, cp) = self.player.pitch.sin_cos();
+        let forward = Vec3::new(cy * cp, sy * cp, sp).normalized();
+        let right = Vec3::new(-sy, cy, 0.0).normalized();
+        let up = right.cross(forward).normalized();
