+                let maxx = sx0.max(sx1).max(sx2).ceil().min(w - 1.0) as i32;
+                let miny = sy0.min(sy1).min(sy2).floor().max(0.0) as i32;
+                let maxy = sy0.max(sy1).max(sy2).ceil().min(h - 1.0) as i32;
+
+                if minx > maxx || miny > maxy {
+                    return;
+                }
