+fn point_segment_distance_sq(px: f32, py: f32, x1: f32, y1: f32, x2: f32, y2: f32) -> f32 {
+    let vx = x2 - x1;
+    let vy = y2 - y1;
+    let wx = px - x1;
+    let wy = py - y1;
+    let len_sq = vx * vx + vy * vy;
+    if len_sq <= 1e-6 {
+        let dx = px - x1;
+        let dy = py - y1;
+        return dx * dx + dy * dy;
+    }
+    let t = ((wx * vx) + (wy * vy)) / len_sq;
+    let t = t.clamp(0.0, 1.0);
+    let proj_x = x1 + t * vx;
+    let proj_y = y1 + t * vy;
+    let dx = px - proj_x;
+    let dy = py - proj_y;
+    dx * dx + dy * dy
+}
