+fn min_wall_distance_sq(x: f32, y: f32, walls: &[WallSeg]) -> f32 {
+    let mut best = f32::INFINITY;
+    for seg in walls {
+        let dist_sq = point_segment_distance_sq(x, y, seg.x1, seg.y1, seg.x2, seg.y2);
+        if dist_sq < best {
+            best = dist_sq;
+        }
+    }
+    best
+}
